example.code:
#!/usr/bin/env bash # scripts/validate-openapi.sh — pre-commit gate set -euo pipefail SPEC="${1:-openapi.yaml}"
[[ -f "$SPEC" ]] || { echo "no spec at $SPEC"; exit 1; }
# 1. structural npx --yes @stoplight/spectral-cli lint "$SPEC" --ruleset .spectral.yaml \ || { echo "spectral failed"; exit 1; }
# 2. redocly governance npx --yes @redocly/cli lint "$SPEC" \ || { echo "redocly failed"; exit 1; }
# 3. examples match schema npx --yes openapi-examples-validator "$SPEC" \ || { echo "examples mismatch"; exit 1; }
# 4. breaking changes vs main if git rev-parse origin/main >/dev/null 2>&1; then git show origin/main:"$SPEC" > /tmp/main-spec.yaml 2>/dev/null \ && oasdiff breaking /tmp/main-spec.yaml "$SPEC" --fail-on ERR \ || true fi
echo "openapi validation OK"
